INSERT INTO timesheet_entries (employee_id, week_start, project_id, task_name, hours_json, is_overhead)
SELECT
  src.emp_id::uuid,
  src.week_start::date,
  p.id,
  NULLIF(src.task_name, ''),
  src.hours_json,
  false
FROM src
JOIN projects p ON p.name = src.proj_name
ON CONFLICT (week_start, employee_id, task_name, project_id) DO NOTHING;
